    "demo-btn-hist1": "+ 1行の履歴",
    "demo-btn-hist2": "+ 2行の履歴",
    "demo-label-setting": "インタラクティブプレビュー：字幕翻訳とバイリンガル切り替え",
    "demo-btn-bilingual": "バイリンガル対照 (繁中)",
